import { InlineKeyboard } from "grammy";
import { upsertUser } from "../services/stateStore.js";

export default function register(bot) {
  bot.command("start", async (ctx) => {
    const telegramUserId = ctx.from?.id;
    const chatId = ctx.chat?.id;
    await upsertUser({ telegramUserId, chatId, settings: {} });

    const kb = new InlineKeyboard()
      .text("Price", "menu:price")
      .text("Watchlist", "menu:watchlist")
      .row()
      .text("Alerts", "menu:alerts")
      .text("New Pairs", "menu:newpairs")
      .row()
      .text("Settings", "menu:settings")
      .text("Help", "menu:help");

    await ctx.reply(
      "Welcome to Solana Alert Watcher.\n\nYou can look up prices by token symbol or mint address.\nIf a symbol matches multiple tokens, you may need to use the mint.",
      { reply_markup: kb }
    );
  });
}

watchlist.js.content:
import { InlineKeyboard } from "grammy";
import { resolveToken, getTokenPriceUsd } from "../services/priceService.js";
import { getWatchlist, addToWatchlist, removeFromWatchlist } from "../services/stateStore.js";
import { shortMint, fmtUsd } from "../lib/format.js";
import { setConvoState, getConvoState, clearConvoState } from "../lib/convoState.js";

async function showWatchlist(ctx) {
  const wl = await getWatchlist(ctx.from?.id);
  const items = Array.isArray(wl.items) ? wl.items : [];

  if (items.length === 0) {
    const kb = new InlineKeyboard().text("Add Token", "watchlist:add");
    await ctx.reply("Your watchlist is empty.", { reply_markup: kb });
    return;
  }

  const kb = new InlineKeyboard()
    .text("Add Token", "watchlist:add")
    .text("Remove Token", "watchlist:remove")
    .row();

  let msg = "Your watchlist:\n";
  for (const it of items.slice(0, 30)) {
    const pr = await getTokenPriceUsd(it.mint, { bypassCache: false });
    const line = (it.symbol || it.name || shortMint(it.mint)) + ": " + (pr.ok ? fmtUsd(pr.priceUsd) : "N/A");
    msg += "\n" + line + " (" + shortMint(it.mint) + ")";

    kb
      .text("Price", "refresh_price:" + it.mint)
      .text("Remove", "remove_watchlist:" + it.mint)
      .row()
      .text("Set Alert", "set_alert_above:" + it.mint)
      .row();
  }

  await ctx.reply(msg, { reply_markup: kb });
}

export default function register(bot) {
  bot.command("watchlist", async (ctx) => {
    const text = String(ctx.message?.text || "");
    const parts = text.split(/\s+/).slice(1);
    const sub = String(parts[0] || "").toLowerCase();
    const arg = parts.slice(1).join(" ").trim();

    if (!sub) {
      await showWatchlist(ctx);
      return;
    }

    if (sub === "list") {
      await showWatchlist(ctx);
      return;
    }

    if (sub === "add") {
      if (!arg) {
        await ctx.reply("Usage: /watchlist add <symbol|mint>");
        return;
      }
      const r = await resolveToken(arg);
      if (!r.ok) {
        await ctx.reply("Could not resolve token. Try a mint address.");
        return;
      }
      const res = await addToWatchlist(ctx.from?.id, r.token);
      await ctx.reply(res.already ? "Already in your watchlist." : "Added to your watchlist.");
      return;
    }

    if (sub === "remove") {
      if (!arg) {
        await ctx.reply("Usage: /watchlist remove <symbol|mint>");
        return;
      }
      const r = await resolveToken(arg);
      if (!r.ok) {
        await ctx.reply("Could not resolve token. Try a mint address.");
        return;
      }
      await removeFromWatchlist(ctx.from?.id, r.token.mint);
      await ctx.reply("Removed from your watchlist (if it was present).");
      return;
    }

    await ctx.reply("Usage: /watchlist [list|add|remove]");
  });

  bot.callbackQuery("watchlist:add", async (ctx) => {
    await ctx.answerCallbackQuery();
    setConvoState(ctx.from?.id, { mode: "watchlist_add" });
    await ctx.reply("Send the token symbol or mint to add to your watchlist.");
  });

  bot.callbackQuery("watchlist:remove", async (ctx) => {
    await ctx.answerCallbackQuery();
    setConvoState(ctx.from?.id, { mode: "watchlist_remove" });
    await ctx.reply("Send the token symbol or mint to remove from your watchlist.");
  });

  bot.callbackQuery(/^remove_watchlist:(.+)$/, async (ctx) => {
    const mint = String(ctx.match?.[1] || "").trim();
    await ctx.answerCallbackQuery();
    if (!mint) return;
    await removeFromWatchlist(ctx.from?.id, mint);
    await ctx.reply("Removed from your watchlist (if it was present)." );
  });

  bot.on("message:text", async (ctx, next) => {
    const raw = String(ctx.message?.text || "");
    if (raw.startsWith("/")) return next();

    const s = getConvoState(ctx.from?.id);
    if (!s) return next();

    const input = raw.trim();

    if (s.mode === "watchlist_add") {
      clearConvoState(ctx.from?.id);
      const r = await resolveToken(input);
      if (!r.ok) {
        await ctx.reply("Could not resolve token. Try a mint address.");
        return;
      }
      const res = await addToWatchlist(ctx.from?.id, r.token);
      await ctx.reply(res.already ? "Already in your watchlist." : "Added to your watchlist.");
      return;
    }

    if (s.mode === "watchlist_remove") {
      clearConvoState(ctx.from?.id);
      const r = await resolveToken(input);
      if (!r.ok) {
        await ctx.reply("Could not resolve token. Try a mint address.");
        return;
      }
      await removeFromWatchlist(ctx.from?.id, r.token.mint);
      await ctx.reply("Removed from your watchlist (if it was present)." );
      return;
    }

    return next();
  });
}

menus.js.content:
import { InlineKeyboard } from "grammy";
import { setNewPairsNotifications, getLatestRaydiumPairs } from "../services/stateStore.js";
import { shortMint } from "../lib/format.js";
import { cfg } from "../lib/config.js";

export function registerMenus(bot) {
  bot.callbackQuery(/^menu:(.+)$/, async (ctx) => {
    const which = String(ctx.match?.[1] || "");
    await ctx.answerCallbackQuery();

    if (which === "help") {
      await ctx.reply("Type /help to see commands and examples.");
      return;
    }

    if (which === "price") {
      await ctx.reply("Use /price <symbol|mint>. Example: /price SOL");
      return;
    }

    if (which === "watchlist") {
      await ctx.reply("Opening watchlist…\nUse /watchlist to manage it.");
      return;
    }

    if (which === "alerts") {
      await ctx.reply("Opening alerts…\nUse /alerts to manage alerts.");
      return;
    }

    if (which === "settings") {
      await ctx.reply("Settings are minimal right now. New pairs notifications are configured in the New Pairs menu.");
      return;
    }

    if (which === "newpairs") {
      const kb = new InlineKeyboard()
        .text("Show Latest", "newpairs:latest")
        .row()
        .text("Enable Notifications", "newpairs_enable")
        .text("Disable Notifications", "newpairs_disable");

      await ctx.reply("New Pairs menu:", { reply_markup: kb });
      return;
    }

    await ctx.reply("Menu not available.");
  });

  bot.callbackQuery("newpairs_enable", async (ctx) => {
    await ctx.answerCallbackQuery();
    await setNewPairsNotifications(ctx.from?.id, true);
    await ctx.reply("New pair notifications enabled.");
  });

  bot.callbackQuery("newpairs_disable", async (ctx) => {
    await ctx.answerCallbackQuery();
    await setNewPairsNotifications(ctx.from?.id, false);
    await ctx.reply("New pair notifications disabled.");
  });

  bot.callbackQuery("newpairs:latest", async (ctx) => {
    await ctx.answerCallbackQuery({ text: "Loading…" });
    const limit = Number(cfg.NEW_PAIRS_LATEST_LIMIT || 15);
    const pairs = await getLatestRaydiumPairs(limit);
    if (!pairs.length) {
      await ctx.reply("No new pairs discovered yet. Check back soon.");
      return;
    }

    let msg = "Latest discovered pairs:\n";
    for (const p of pairs.slice(0, 20)) {
      msg += "\nPair: " + shortMint(p.pairId) + "\nBase: " + shortMint(p.baseMint) + "\nQuote: " + shortMint(p.quoteMint);
      msg += "\nTime: " + (p.discoveredAt ? new Date(p.discoveredAt).toISOString() : "N/A") + "\n";
    }

    await ctx.reply(msg);
  });
}

index.js.content:
import "dotenv/config";

import { run } from "@grammyjs/runner";
import { cfg } from "./lib/config.js";
import { logInfo, logWarn, logError, safeErr } from "./lib/log.js";
import { createBot } from "./bot.js";
import { registerCommands } from "./commands/loader.js";
import { getDb, ensureIndexes } from "./lib/db.js";
import { buildBotProfile } from "./lib/botProfile.js";
import { startAlertPoller } from "./pollers/alertPoller.js";
import { startRaydiumScanner } from "./pollers/raydiumScanner.js";

process.on("unhandledRejection", (r) => {
  console.error("UnhandledRejection:", r);
  process.exit(1);
});
process.on("uncaughtException", (e) => {
  console.error("UncaughtException:", e);
  process.exit(1);
});

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

async function boot() {
  logInfo("boot start", {
    nodeEnv: process.env.NODE_ENV || "",
    TELEGRAM_BOT_TOKEN_set: !!cfg.TELEGRAM_BOT_TOKEN,
    MONGODB_URI_set: !!cfg.MONGODB_URI,
    PRICE_API_BASE_URL_set: !!cfg.PRICE_API_BASE_URL,
    RAYDIUM_API_BASE_URL_set: !!cfg.RAYDIUM_API_BASE_URL,
  });

  if (!cfg.TELEGRAM_BOT_TOKEN) {
    console.error("TELEGRAM_BOT_TOKEN is required. Add it to your env and redeploy.");
    process.exit(1);
  }

  const profile = buildBotProfile();
  logInfo("bot profile", { profile });

  if (cfg.MONGODB_URI) {
    try {
      const db = await getDb(cfg.MONGODB_URI);
      await ensureIndexes(db);
    } catch (e) {
      logWarn("mongo unavailable, continuing without persistence", { err: safeErr(e) });
    }
  } else {
    logWarn("MONGODB_URI missing, running with in-memory state", {});
  }

  const bot = createBot(cfg.TELEGRAM_BOT_TOKEN);

  await registerCommands(bot);

  try {
    await bot.api.setMyCommands([
      { command: "start", description: "Welcome & main menu" },
      { command: "help", description: "How to use the bot" },
      { command: "price", description: "Price lookup" },
      { command: "watchlist", description: "Manage watchlist" },
      { command: "alerts", description: "Manage alerts" },
      { command: "alert", description: "Create an alert" },
      { command: "reset", description: "Clear your watchlist and alerts" },
    ]);
  } catch (e) {
    logWarn("setMyCommands failed", { err: safeErr(e) });
  }

  bot.catch((err) => {
    logError("bot error", { err: safeErr(err?.error || err) });
  });

  let stopAlert = null;
  let stopRaydium = null;

  try {
    stopAlert = startAlertPoller(bot);
    stopRaydium = startRaydiumScanner(bot);
  } catch (e) {
    logWarn("pollers failed to start", { err: safeErr(e) });
  }

  // Memory log (once per minute)
  setInterval(() => {
    const m = process.memoryUsage();
    console.log("[mem]", {
      rssMB: Math.round(m.rss / 1e6),
      heapUsedMB: Math.round(m.heapUsed / 1e6),
    });
  }, 60_000).unref();

  // Polling reliability: delete webhook and retry on 409.
  let backoff = 2000;
  const maxBackoff = 20_000;

  while (true) {
    try {
      logInfo("polling start", { concurrency: 1 });
      await bot.api.deleteWebhook({ drop_pending_updates: true });

      const runner = run(bot, { concurrency: 1 });
      await runner.task();

      // If runner.task resolves, treat it as unexpected stop.
      logWarn("polling stopped unexpectedly", {});
      backoff = Math.min(maxBackoff, backoff * 2);
      await sleep(backoff);
      continue;
    } catch (e) {
      const msg = safeErr(e);
      if (String(msg).includes("409") || String(msg).toLowerCase().includes("conflict")) {
        logWarn("polling conflict (409), retrying", { backoffMs: backoff, err: msg });
        await sleep(backoff);
        backoff = Math.min(maxBackoff, backoff * 2);
        continue;
      }

      logError("polling fatal error", { err: msg });
      if (typeof stopAlert === "function") stopAlert();
      if (typeof stopRaydium === "function") stopRaydium();
      process.exit(1);
    }
  }
}

boot().catch((e) => {
  console.error("Boot error:", safeErr(e));
  process.exit(1);
});

ai.js.content:
function trimSlash(u) {
  u = String(u || "");
  while (u.endsWith("/")) u = u.slice(0, -1);
  return u;
}

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

async function safeRead(r) {
  const text = await r.text();
  let json = null;
  try { json = JSON.parse(text); } catch {}
  return { text, json };
}

function notConfigured(message) {
  return { ok: false, status: 412, json: null, text: "", error: message };
}

function withTimeout(ms) {
  const ctrl = new AbortController();
  const t = setTimeout(() => ctrl.abort(), ms);
  return { ctrl, clear: () => clearTimeout(t) };
}

function pickTimeout(cfg) {
  const v = Number(cfg?.AI_TIMEOUT_MS || cfg?.AI_TIMEOUT || 20000);
  return Number.isFinite(v) && v > 0 ? v : 20000;
}

function pickModel(cfg, override) {
  const m = String(override || cfg?.AI_MODEL || "").trim();
  return m || undefined;
}

function isRetryableStatus(status) {
  // 408: request timeout, 429: rate, 500/502/503/504 transient
  return status === 408 || status === 429 || status === 500 || status === 502 || status === 503 || status === 504;
}

function redact(s) {
  s = String(s || "");
  if (s.length <= 400) return s;
  return s.slice(0, 400) + "…";
}

function web3Mode(cfg) {
  const m = String(cfg?.WEB3_CHAT_MODE || "auto").trim().toLowerCase();
  return (m === "on" || m === "off" || m === "auto") ? m : "auto";
}

async function aiGet(cfg, path, opts = {}) {
  const base = trimSlash(cfg?.COOKMYBOTS_AI_ENDPOINT || "");
  const key = String(cfg?.COOKMYBOTS_AI_KEY || "");
  const DEBUG = String(cfg?.AI_DEBUG || "") === "1";
  if (!base || !key) return notConfigured("AI_NOT_CONFIGURED (missing COOKMYBOTS_AI_ENDPOINT/COOKMYBOTS_AI_KEY)");

  const timeoutMs = Number(opts.timeoutMs || pickTimeout(cfg));
  const url = base + String(path || "");

  const { ctrl, clear } = withTimeout(timeoutMs);
  try {
    if (DEBUG) console.log("[aiGet] ->", url);
    const r = await fetch(url, { method: "GET", headers: { Authorization: "Bearer " + key }, signal: ctrl.signal });
    const { text, json } = await safeRead(r);
    if (!r.ok) {
      const err = json?.error || json?.message || text || "AI_ERROR";
      return { ok: false, status: r.status, json, text, error: String(err) };
    }
    return { ok: true, status: r.status, json, text, error: null };
  } catch (e) {
    const msg = e?.name === "AbortError" ? "AI_TIMEOUT" : (e?.message || "AI_NETWORK_ERROR");
    return { ok: false, status: e?.name === "AbortError" ? 408 : 0, json: null, text: "", error: String(msg) };
  } finally {
    clear();
  }
}

async function routeChat(cfg, userText, systemHint) {
  // Uses the normal gateway /chat as a fast classifier.
  // Returns: "web3" | "normal"
  const base = trimSlash(cfg?.COOKMYBOTS_AI_ENDPOINT || "");
  const key = String(cfg?.COOKMYBOTS_AI_KEY || "");
  if (!base || !key) return "normal";

  const timeoutMs = Math.min(8000, pickTimeout(cfg));
  const { ctrl, clear } = withTimeout(timeoutMs);

  const sys = [
    "You are a routing classifier for a bot.",
    "Decide if the user's message should go to a Web3 specialist model (ChainGPT) or a normal general AI model.",
    "",
    "Return ONLY valid JSON:",
    '{"route":"web3"}',
    "or",
    '{"route":"normal"}',
    "",
    "Route to web3 if the user asks about: crypto, tokens, Solidity, smart contracts, audits, DeFi, NFTs, wallets, chains, bridges, gas, DEXs, on-chain tools or anything related to blockchain.",
    "Otherwise route to normal.",
    "",
    "Extra context (bot/system hint):",
    String(systemHint || "").slice(0, 800),
  ].join("
");

  try {
    const r = await fetch(base + "/chat", {
      method: "POST",
      headers: {
        Authorization: "Bearer " + key,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        messages: [
          { role: "system", content: sys },
          { role: "user", content: String(userText || "").slice(0, 2000) },
        ],
        model: pickModel(cfg, ""), // let gateway default or AI_MODEL
        meta: { purpose: "route" },
      }),
      signal: ctrl.signal,
    });

    const { text, json } = await safeRead(r);
    if (!r.ok) return "normal";

    // Try common shapes: gateway might return {text} or OpenAI-like {choices}
    const out =
      (json && (json.text || json.message)) ||
      (json && json.choices && json.choices[0] && json.choices[0].message && json.choices[0].message.content) ||
      text ||
      "";

    const raw = String(out || "").trim();

    // Parse JSON safely
    try {
      const obj = JSON.parse(raw);
      const route = String(obj?.route || "").toLowerCase();
      return route === "web3" ? "web3" : "normal";
    } catch {
      // If model returned non-JSON, fallback to normal
      return "normal";
    }
  } catch {
    return "normal";
  } finally {
    clear();
  }
}

/**
 * Low-level gateway call.
 * Always returns: { ok, status, json, text, error }
 * - json is parsed response body (if JSON)
 * - error is a short string for logs/UI
 */
export async function aiCall(cfg, path, body, opts = {}) {
  const base = trimSlash(cfg?.COOKMYBOTS_AI_ENDPOINT || "");
  const key = String(cfg?.COOKMYBOTS_AI_KEY || "");
  const DEBUG = String(cfg?.AI_DEBUG || "") === "1";

  if (!base || !key) return notConfigured("AI_NOT_CONFIGURED (missing COOKMYBOTS_AI_ENDPOINT/COOKMYBOTS_AI_KEY)");

  const timeoutMs = Number(opts.timeoutMs || pickTimeout(cfg));
  const retries = Number.isFinite(opts.retries) ? Number(opts.retries) : 1; // default 1 retry
  const backoffMs = Number.isFinite(opts.backoffMs) ? Number(opts.backoffMs) : 750;

  const url = base + String(path || "");
  const started = Date.now();

  let attempt = 0;
  while (true) {
    attempt++;

    const { ctrl, clear } = withTimeout(timeoutMs);
    try {
      if (DEBUG) console.log("[aiCall] ->", url, { attempt, timeoutMs });

      const r = await fetch(url, {
        method: "POST",
        headers: {
          Authorization: "Bearer " + key,
          "Content-Type": "application/json",
        },
        body: JSON.stringify(body || {}),
        signal: ctrl.signal,
      });

      const { text, json } = await safeRead(r);

      if (!r.ok) {
        const err = json?.error || json?.message || text || "AI_ERROR";
        const out = { ok: false, status: r.status, json, text, error: String(err) };

        if (DEBUG) {
          const ms = Date.now() - started;
          console.warn("[aiCall] <- fail", { status: r.status, ms, attempt, err: redact(err) });
        }

        // Retry transient errors
        if (attempt <= retries && isRetryableStatus(r.status)) {
          await sleep(backoffMs * attempt);
          continue;
        }

        return out;
      }

      if (DEBUG) {
        const ms = Date.now() - started;
        console.log("[aiCall] <- ok", { status: r.status, ms, attempt });
      }

      return { ok: true, status: r.status, json, text, error: null };
    } catch (e) {
      const msg = e?.name === "AbortError" ? "AI_TIMEOUT" : (e?.message || "AI_NETWORK_ERROR");
      const out = { ok: false, status: e?.name === "AbortError" ? 408 : 0, json: null, text: "", error: String(msg) };

      if (DEBUG) {
        const ms = Date.now() - started;
        console.warn("[aiCall] <- exception", { ms, attempt, err: redact(msg) });
      }

      // Retry network/timeout issues (status 0/408)
      if (attempt <= retries) {
        await sleep(backoffMs * attempt);
        continue;
      }

      return out;
    } finally {
      clear();
    }
  }
}

/**
 * CHAT
 * Backward compatible:
 * 1) aiChat(cfg, "hello", { model, meta, system })
 * 2) aiChat(cfg, { messages:[...], model, meta })
 *
 * Returns: { ok, status, json, text, error }
 */
export async function aiChat(cfg, input, opts = {}) {
  // Signature (cfg, { messages, model, meta })
  if (input && typeof input === "object" && Array.isArray(input.messages)) {
    const model = pickModel(cfg, input.model);
    return aiCall(cfg, "/chat", {
      messages: input.messages,
      model,
      meta: input.meta || undefined,
    }, opts);
  }

  // Signature (cfg, "prompt")
  const userText = String(input || "");
  const system = String(opts.system || "You are a helpful assistant.");
  const model = pickModel(cfg, opts.model);

  return aiCall(cfg, "/chat", {
    messages: [
      { role: "system", content: system },
      { role: "user", content: userText },
    ],
    model,
    meta: opts.meta || undefined,
  }, opts);
}

// IMAGE
export async function aiImage(cfg, { prompt, size = "1024x1024", n = 1, model = "", meta } = {}, opts = {}) {
  const m = pickModel(cfg, model);
  return aiCall(cfg, "/image", { prompt, size, n, model: m, meta: meta || undefined }, opts);
}

// VISION
export async function aiVision(cfg, { prompt, imageUrl, model = "", meta } = {}, opts = {}) {
  const m = pickModel(cfg, model);
  return aiCall(cfg, "/vision", { prompt, imageUrl, model: m, meta: meta || undefined }, opts);
}

// EMBEDDINGS
export async function aiEmbeddings(cfg, { input, model = "", meta } = {}, opts = {}) {
  const m = pickModel(cfg, model);
  return aiCall(cfg, "/embeddings", { input, model: m, meta: meta || undefined }, opts);
}

// WEB SEARCH
export async function aiWebSearch(cfg, { query, meta } = {}, opts = {}) {
  return aiCall(cfg, "/web-search", { query, meta: meta || undefined }, opts);
}

// SPEECH
export async function aiSpeechTts(cfg, { text, voice = "alloy", format = "mp3", model = "", meta } = {}, opts = {}) {
  const m = pickModel(cfg, model);
  return aiCall(cfg, "/speech/tts", { text, voice, format, model: m, meta: meta || undefined }, opts);
}

export async function aiSpeechStt(cfg, { audioBase64, mimeType = "audio/mpeg", filename = "audio.mp3", durationSeconds = 0, model = "", meta } = {}, opts = {}) {
  const m = pickModel(cfg, model);
  return aiCall(cfg, "/speech/stt", { audioBase64, mimeType, filename, durationSeconds, model: m, meta: meta || undefined }, opts);
}

// VIDEO
export async function aiVideoCreate(cfg, { prompt, seconds = 4, size = "1024x576", model = "", meta } = {}, opts = {}) {
  const m = pickModel(cfg, model);
  return aiCall(cfg, "/video/create", { prompt, seconds, size, model: m, meta: meta || undefined }, opts);
}

/**
 * Video status is GET in many gateways.
 * If your gateway is POST-only, you can keep it as GET via fetch() here.
 */
export async function aiVideoStatus(cfg, jobId, opts = {}) {
  const base = trimSlash(cfg?.COOKMYBOTS_AI_ENDPOINT || "");
  const key = String(cfg?.COOKMYBOTS_AI_KEY || "");
  const DEBUG = String(cfg?.AI_DEBUG || "") === "1";

  if (!base || !key) return notConfigured("AI_NOT_CONFIGURED (missing COOKMYBOTS_AI_ENDPOINT/COOKMYBOTS_AI_KEY)");

  const timeoutMs = Number(opts.timeoutMs || pickTimeout(cfg));
  const url = base + "/video/" + encodeURIComponent(String(jobId || ""));

  const { ctrl, clear } = withTimeout(timeoutMs);
  try {
    if (DEBUG) console.log("[aiVideoStatus] ->", url);

    const r = await fetch(url, {
      headers: { Authorization: "Bearer " + key },
      signal: ctrl.signal,
    });

    const { text, json } = await safeRead(r);

    if (!r.ok) {
      const err = json?.error || json?.message || text || "AI_VIDEO_STATUS_ERROR";
      if (DEBUG) console.warn("[aiVideoStatus] failed:", r.status, redact(err));
      return { ok: false, status: r.status, json, text, error: String(err) };
    }

    return { ok: true, status: r.status, json, text, error: null };
  } catch (e) {
    const msg = e?.name === "AbortError" ? "AI_TIMEOUT" : (e?.message || "AI_NETWORK_ERROR");
    if (DEBUG) console.warn("[aiVideoStatus] exception:", redact(msg));
    return { ok: false, status: e?.name === "AbortError" ? 408 : 0, json: null, text: "", error: String(msg) };
  } finally {
    clear();
  }
}

export async function aiChainGptChat(cfg, { mode = "web3", question, meta } = {}, opts = {}) {
  const m = web3Mode(cfg);
  if (m === "off") return notConfigured("WEB3_DISABLED (WEB3_CHAT_MODE=off)");

  // mode: "web3" | "smart_contract_generator" | "smart_contract_auditor"
  return aiCall(cfg, "/chaingpt/chat", {
    mode: String(mode || "web3"),
    question: String(question || ""),
    meta: meta || undefined,
  }, opts);
}

export async function aiChainGptNews(cfg, { limit = 5 } = {}, opts = {}) {
  const m = web3Mode(cfg);
  if (m === "off") return notConfigured("WEB3_DISABLED (WEB3_CHAT_MODE=off)");
  const q = Number(limit || 5);
  const lim = Number.isFinite(q) ? Math.max(1, Math.min(q, 20)) : 5;
  return aiGet(cfg, "/chaingpt/news?limit=" + encodeURIComponent(String(lim)), opts);
}

export async function aiChainGptNftImage(cfg, { prompt, model = "velogen", steps = 2, width = 512, height = 512, enhance = "1x", meta } = {}, opts = {}) {
  const m = web3Mode(cfg);
  if (m === "off") return notConfigured("WEB3_DISABLED (WEB3_CHAT_MODE=off)");

  return aiCall(cfg, "/chaingpt/nft/image", {
    prompt: String(prompt || ""),
    model: String(model || "velogen"),
    steps: Number(steps || 2),
    width: Number(width || 512),
    height: Number(height || 512),
    enhance: String(enhance || "1x"),
    meta: meta || undefined,
  }, opts);
}

// Convenience: auto-route to ChainGPT if it looks web3, else normal aiChat()
export async function aiSmartChat(cfg, userText, { system = "", meta = {}, retries = 1 } = {}) {
  const m = web3Mode(cfg);

  // Forced modes
  if (m === "on") {
    return aiChainGptChat(cfg, { mode: "web3", question: String(userText || ""), meta }, { retries });
  }
  if (m === "off") {
    return aiChat(cfg, String(userText || ""), { system: system || "You are a helpful assistant.", meta, retries });
  }

  // AUTO mode: AI decides route
  const route = await routeChat(cfg, userText, system);

  if (route === "web3") {
    return aiChainGptChat(cfg, { mode: "web3", question: String(userText || ""), meta }, { retries });
  }

  return aiChat(cfg, String(userText || ""), { system: system || "You are a helpful assistant.", meta, retries });
}

