      import { getDb } from "./db.js";

const COL = "memory_messages";

export async function addTurn({ mongoUri, platform, userId, chatId, role, text }) {
  const db = await getDb(mongoUri);
  const doc = {
    platform,
    userId: String(userId),
    chatId: chatId ? String(chatId) : "",
    role,
    text: String(text || "").slice(0, 4000),
    ts: new Date(),
  };

  if (!db) return; // allow bot to run without DB
  await db.collection(COL).insertOne(doc);
}

export async function getRecentTurns({ mongoUri, platform, userId, chatId, limit = 14 }) {
  const db = await getDb(mongoUri);
  if (!db) return [];

  const q = {
    platform,
    userId: String(userId),
  };
  if (chatId) q.chatId = String(chatId);

  const rows = await db
    .collection(COL)
    .find(q)
    .sort({ ts: -1 })
    .limit(limit)
    .toArray();

  // return chronological
  return rows.reverse().map((r) => ({ role: r.role, text: r.text }));
}

export async function clearUserMemory({ mongoUri, platform, userId, chatId }) {
  const db = await getDb(mongoUri);
  if (!db) return;

  const q = { platform, userId: String(userId) };
  if (chatId) q.chatId = String(chatId);

  await db.collection(COL).deleteMany(q);
}

ttlCache.js.content:
export function createTtlCache({ ttlMs = 60_000, max = 5000 } = {}) {
  const map = new Map();

  function prune() {
    const now = Date.now();
    for (const [k, v] of map) {
      if (!v || v.expiresAt <= now) map.delete(k);
    }
    while (map.size > max) {
      const first = map.keys().next().value;
      map.delete(first);
    }
  }

  return {
    get(key) {
      const v = map.get(key);
      if (!v) return undefined;
      if (v.expiresAt <= Date.now()) {
        map.delete(key);
        return undefined;
      }
      return v.value;
    },
    set(key, value, overrideTtlMs) {
      const ms = Number.isFinite(overrideTtlMs) ? overrideTtlMs : ttlMs;
      map.set(key, { value, expiresAt: Date.now() + ms });
      if (map.size > max) prune();
    },
    delete(key) {
      map.delete(key);
    },
    prune
  };
}

