import { cfg } from "../lib/config.js";
import { logInfo, logWarn, logError, safeErr } from "../lib/log.js";
import { fetchActiveAlertsAll, markAlertTriggered } from "../services/stateStore.js";
import { getTokenPriceUsd } from "../services/priceService.js";
import { fmtUsd, shortMint } from "../lib/format.js";

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

export function startAlertPoller(bot) {
  let running = true;
  let backoffMs = 0;

  const intervalMs = Math.max(5, Number(cfg.ALERT_POLL_INTERVAL_SECONDS || 30)) * 1000;

  logInfo("alertPoller start", { intervalMs });

  (async () => {
    while (running) {
      const cycleStarted = Date.now();

      try {
        logInfo("alertPoller cycle", {});

        const alerts = await fetchActiveAlertsAll();
        logInfo("alertPoller fetched alerts", { active: alerts.length });

        const byMint = new Map();
        for (const a of alerts) {
          const mint = String(a.mint || "");
          if (!mint) continue;
          const arr = byMint.get(mint) || [];
          arr.push(a);
          byMint.set(mint, arr);
        }

        let triggered = 0;
        for (const [mint, arr] of byMint) {
          const pr = await getTokenPriceUsd(mint, { bypassCache: false });
          if (!pr.ok) {
            logWarn("alertPoller price unavailable", { mint: shortMint(mint) });
            continue;
          }
          const price = pr.priceUsd;

          for (const a of arr) {
            const dir = String(a.direction || "");
            const target = Number(a.targetPriceUsd);
            if (!Number.isFinite(target)) continue;

            const hit = (dir === "above") ? (price >= target) : (price <= target);
            if (!hit) continue;

            triggered++;

            const chatId = a.chatId || a.telegramUserId;
            const tokenLabel = (a.symbol || a.name || shortMint(mint));

            try {
              await bot.api.sendMessage(
                chatId,
                [
                  "Alert triggered:",
                  tokenLabel + " (" + shortMint(mint) + ")",
                  "Direction: " + dir.toUpperCase(),
                  "Target: " + fmtUsd(target),
                  "Current: " + fmtUsd(price),
                ].join("\n"),
                {
                  reply_markup: {
                    inline_keyboard: [
                      [{ text: "Remove Alert", callback_data: "remove_alert:" + String(a._id) }],
                      [{ text: "Add Another Alert", callback_data: "alerts:add" }],
                      [{ text: "View Price", callback_data: "refresh_price:" + mint }],
                    ],
                  },
                }
              );
            } catch (e) {
              logWarn("alertPoller sendMessage failed", { err: safeErr(e) });
            }

            try {
              await markAlertTriggered(String(a._id));
            } catch (e) {
              logError("alertPoller mark triggered failed", { err: safeErr(e) });
            }
          }
        }

        logInfo("alertPoller cycle done", { triggered, ms: Date.now() - cycleStarted });
        backoffMs = 0;
      } catch (e) {
        logError("alertPoller cycle failed", { err: safeErr(e) });
        backoffMs = Math.min(20_000, Math.max(2000, backoffMs ? backoffMs * 2 : 2000));
      }

      const waitMs = Math.max(500, intervalMs + backoffMs - (Date.now() - cycleStarted));
      await sleep(waitMs);
    }
  })();

  return () => {
    running = false;
  };
}

raydiumScanner.js.content:
import { cfg } from "../lib/config.js";
import { logInfo, logWarn, logError, safeErr } from "../lib/log.js";
import { fetchLatestPairs } from "../services/raydiumService.js";
import {
  getRaydiumState,
  updateRaydiumStateLastSeen,
  insertRaydiumPairs,
  getUsersWithNewPairsEnabled,
} from "../services/stateStore.js";
import { shortMint } from "../lib/format.js";

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

export function startRaydiumScanner(bot) {
  let running = true;
  let backoffMs = 0;

  const intervalMs = Math.max(10, Number(cfg.RAYDIUM_SCAN_INTERVAL_SECONDS || 120)) * 1000;
  logInfo("raydiumScanner start", { intervalMs });

  (async () => {
    while (running) {
      const cycleStarted = Date.now();

      try {
        logInfo("raydiumScanner cycle", {});

        const st = await getRaydiumState();
        const seen = new Set(Array.isArray(st.lastSeenPairIds) ? st.lastSeenPairIds : []);

        const latest = await fetchLatestPairs({ bypassCache: false });
        if (!latest.ok) {
          logWarn("raydiumScanner fetch failed", { error: latest.error });
          throw new Error(latest.error || "RAYDIUM_API_DOWN");
        }

        const pairs = latest.pairs || [];
        const newOnes = [];
        for (const p of pairs) {
          if (!p.pairId) continue;
          if (!seen.has(p.pairId)) newOnes.push(p);
        }

        // Sync strategy: on first boot, don't spam backlog.
        if (!Array.isArray(st.lastSeenPairIds) || st.lastSeenPairIds.length === 0) {
          const ids = pairs.slice(0, 200).map((p) => p.pairId);
          await updateRaydiumStateLastSeen(ids);
          logInfo("raydiumScanner synced to now", { count: ids.length });
          backoffMs = 0;
        } else {
          const ids = pairs.slice(0, 200).map((p) => p.pairId);
          await updateRaydiumStateLastSeen(ids);

          if (newOnes.length) {
            await insertRaydiumPairs(newOnes);
          }

          const users = await getUsersWithNewPairsEnabled();
          let sent = 0;

          for (const p of newOnes.slice(0, 25)) {
            const msg = [
              "New Raydium pair discovered:",
              "Pair: " + shortMint(p.pairId),
              "Base: " + shortMint(p.baseMint),
              "Quote: " + shortMint(p.quoteMint),
            ].join("\n");

            const kb = {
              inline_keyboard: [
                [{ text: "Price", callback_data: "refresh_price:" + p.baseMint }],
                [{ text: "Add to Watchlist", callback_data: "add_watchlist:" + p.baseMint }],
              ],
            };

            for (const u of users) {
              const chatId = u.chatId || u.telegramUserId;
              try {
                await bot.api.sendMessage(chatId, msg, { reply_markup: kb });
                sent++;
              } catch (e) {
                logWarn("raydiumScanner send failed", { err: safeErr(e) });
              }
            }
          }

          logInfo("raydiumScanner cycle done", { newPairs: newOnes.length, notified: sent, ms: Date.now() - cycleStarted });
          backoffMs = 0;
        }
      } catch (e) {
        logError("raydiumScanner cycle failed", { err: safeErr(e) });
        backoffMs = Math.min(60_000, Math.max(3000, backoffMs ? backoffMs * 2 : 3000));
      }

      const waitMs = Math.max(500, intervalMs + backoffMs - (Date.now() - cycleStarted));
      await sleep(waitMs);
    }
  })();

  return () => {
    running = false;
  };
}

http.js.content:
import { safeErr, logInfo, logWarn } from "../lib/log.js";

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

export async function httpGetJson(url, { timeoutMs = 15_000, retries = 1, label = "http_get" } = {}) {
  const started = Date.now();
  let attempt = 0;

  while (true) {
    attempt++;
    const ctrl = new AbortController();
    const t = setTimeout(() => ctrl.abort(), timeoutMs);

    try {
      logInfo("api call start", { label, attempt });
      const r = await fetch(url, {
        method: "GET",
        headers: { "User-Agent": "SolanaAlertWatcher/1.0" },
        signal: ctrl.signal,
      });

      const text = await r.text();
      let json = null;
      try {
        json = JSON.parse(text);
      } catch {
        json = null;
      }

      if (!r.ok) {
        const errMsg = json?.error?.message || json?.message || text || "HTTP_ERROR";
        logWarn("api call fail", { label, status: r.status, ms: Date.now() - started, err: String(errMsg).slice(0, 200) });

        if (attempt <= retries && (r.status === 408 || r.status === 429 || (r.status >= 500 && r.status < 600))) {
          await sleep(400 * attempt);
          continue;
        }
        const e = new Error(String(errMsg));
        e.status = r.status;
        throw e;
      }

      logInfo("api call success", { label, status: r.status, ms: Date.now() - started });
      return json;
    } catch (e) {
      const msg = e?.name === "AbortError" ? "TIMEOUT" : safeErr(e);
      logWarn("api call exception", { label, attempt, ms: Date.now() - started, err: String(msg).slice(0, 200) });
      if (attempt <= retries) {
        await sleep(400 * attempt);
        continue;
      }
      throw e;
    } finally {
      clearTimeout(t);
    }
  }
}

priceService.js.content:
import { cfg } from "../lib/config.js";
import { createTtlCache } from "../lib/ttlCache.js";
import { logInfo, safeErr } from "../lib/log.js";
import { httpGetJson } from "./http.js";

const ttlMs = Math.max(5, Number(cfg.CACHE_TTL_SECONDS || 60)) * 1000;
const resolveCache = createTtlCache({ ttlMs, max: 4000 });
const priceCache = createTtlCache({ ttlMs: Math.min(ttlMs, 30_000), max: 8000 });

function isSolanaMint(s) {
  const t = String(s || "").trim();
  return /^[1-9A-HJ-NP-Za-km-z]{32,44}$/.test(t);
}

function normalizeSymbol(s) {
  return String(s || "").trim().toUpperCase();
}

export async function resolveToken(input) {
  const raw = String(input || "").trim();
  if (!raw) return { ok: false, error: "EMPTY" };

  if (isSolanaMint(raw)) {
    return { ok: true, token: { mint: raw, symbol: "", name: "", resolvedBy: "mint" } };
  }

  const sym = normalizeSymbol(raw);
  const cached = resolveCache.get("sym:" + sym);
  if (cached) return { ok: true, token: cached };

  try {
    const url = "https://token.jup.ag/all";
    logInfo("api call start", { label: "jupiter_token_list" });
    const list = await httpGetJson(url, { timeoutMs: 20_000, retries: 1, label: "jupiter_token_list" });
    const matches = Array.isArray(list) ? list.filter((t) => String(t?.symbol || "").toUpperCase() === sym) : [];

    if (matches.length === 0) {
      return { ok: false, error: "NOT_FOUND" };
    }

    if (matches.length === 1) {
      const t = matches[0];
      const token = { mint: String(t.address), symbol: String(t.symbol || sym), name: String(t.name || sym), resolvedBy: "symbol" };
      resolveCache.set("sym:" + sym, token);
      return { ok: true, token };
    }

    const options = matches.slice(0, 8).map((t) => ({
      mint: String(t.address),
      symbol: String(t.symbol || sym),
      name: String(t.name || sym),
    }));

    return { ok: false, error: "AMBIGUOUS", options };
  } catch (e) {
    return { ok: false, error: "API_DOWN", detail: safeErr(e) };
  }
}

export async function getTokenPriceUsd(mint, { bypassCache = false } = {}) {
  const m = String(mint || "").trim();
  if (!m) return { ok: false, error: "EMPTY_MINT" };

  const key = "p:" + m;
  if (!bypassCache) {
    const cached = priceCache.get(key);
    if (cached) return { ok: true, ...cached, cached: true };
  }

  const base = String(cfg.PRICE_API_BASE_URL || "").trim();
  if (!base) return { ok: false, error: "API_NOT_CONFIGURED" };

  try {
    const url = base.replace(/\/+$/, "") + "/price?ids=" + encodeURIComponent(m);
    const json = await httpGetJson(url, { timeoutMs: 12_000, retries: 1, label: "jupiter_price" });

    const p = json?.data?.[m]?.price;
    const price = Number(p);
    const ts = new Date();

    if (!Number.isFinite(price)) {
      return { ok: false, error: "NO_PRICE" };
    }

    const out = { priceUsd: price, ts, source: "Jupiter" };
    priceCache.set(key, out);
    return { ok: true, ...out, cached: false };
  } catch (e) {
    const cached = priceCache.get(key);
    if (cached) {
      return { ok: true, ...cached, cached: true, stale: true, warn: "API_DOWN" };
    }
    return { ok: false, error: "API_DOWN", detail: safeErr(e) };
  }
}

export async function getTokenChange24h(mint) {
  // Jupiter /price endpoint does not provide 24h change. Keep optional.
  // If you later add a provider with 24h change, wire it here.
  return { ok: true, change24hPct: null, source: "N/A" };
}

